#include <iostream>
using namespace std;

template<typename T>
struct Node {
    T data;
    Node* parent;
    Node* leftmostChild;
    Node* rightSibling;

    explicit Node(T val)
        : data(val), parent(nullptr),
          leftmostChild(nullptr), rightSibling(nullptr) {}
};

template<typename T>
struct NaryTree {
    Node<T>* root;
    NaryTree() : root(nullptr) {}
};

// Add child as the rightmost child of parent
template<typename T>
void addChild(Node<T>* parent, Node<T>* child) {
    child->parent = parent;
    if (!parent->leftmostChild) {
        parent->leftmostChild = child;
    } else {
        Node<T>* sibling = parent->leftmostChild;
        while (sibling->rightSibling)
            sibling = sibling->rightSibling;
        sibling->rightSibling = child;
    }
}
