#include <queue>
#include <iostream>
using namespace std;

// Preorder traversal
template<typename T>
void preorder(Node<T>* p) {
    if (!p) return;
    cout << p->data << " ";        // visit current
    preorder(p->leftmostChild);    // recurse into children
    preorder(p->rightSibling);     // recurse into siblings
}

// Postorder traversal
template<typename T>
void postorder(Node<T>* p) {
    if (!p) return;
    postorder(p->leftmostChild);   // recurse into children first
    cout << p->data << " ";        // visit current
    postorder(p->rightSibling);    // recurse into siblings
}

// Level-order (BFS) traversal
template<typename T>
void levelOrder(NaryTree<T>& tree) {
    if (!tree.root) return;
    queue<Node<T>*> q;
    q.push(tree.root);
    while (!q.empty()) {
        Node<T>* p = q.front(); q.pop();
        cout << p->data << " ";    // visit
        for (Node<T>* c = p->leftmostChild; c; c = c->rightSibling)
            q.push(c);             // enqueue all children
    }
}
// All three traversals: O(n) time, O(n) space (call stack or queue)
